            adsk::doEvents();
        }
        app->log(resultText);

        // Indicate in a messageBox that the script has finished
        ui->messageBox(
            resultMessage,
            "Library Items Sample\t\t\t\t\t",
            MessageBoxButtonTypes::OKButtonType,
            MessageBoxIconTypes::InformationIconType);
    }

    return true;
